# Category: broken_access_control

from flask import Flask, send_file, abort
import os

app = Flask(__name__)

INVOICE_FOLDER = 'path/to/invoice/folder'

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    try:
        file_path = os.path.join(INVOICE_FOLDER, f'invoice_{invoice_id}.pdf')
        if os.path.exists(file_path):
            return send_file(file_path, as_attachment=True, attachment_filename=f'invoice_{invoice_id}.pdf')
        else:
            abort(404, description="Invoice not found")
    except Exception as e:
        abort(500, description=str(e))

if __name__ == "__main__":
    app.run()